public class TelefonRehberi {
    static Map<String, String> rehber = new HashMap<>();
    static Scanner sc = new Scanner(System.in);

    static void kisiEkle() {
        System.out.print('Isim: ');
        String isim = sc.nextLine();
        System.out.print('Telefon: ');
        String tel = sc.nextLine();
        rehber.put(isim, tel);
        System.out.println(isim + ' rehbere eklendi.');
    }

    static void kisiAra() {
        System.out.print('Aranan isim: ');
        String isim = sc.nextLine();
        if (rehber.containsKey(isim)) {
            System.out.println(isim + ': ' + rehber.get(isim));
        } else {
            System.out.println('Kisi bulunamadi.');
        }
    }

    static void rehberiListele() {
        if (rehber.isEmpty()) {
            System.out.println('Rehber bos.');
            return;
        }
        rehber.forEach((isim, tel) ->
            System.out.println(isim + ': ' + tel));
    }

