    static Scanner sc = new Scanner(System.in);

    static class Urun {
        String ad;
        double fiyat;
        int adet;

        Urun(String ad, double fiyat, int adet) {
            this.ad = ad;
            this.fiyat = fiyat;
            this.adet = adet;
        }
