import java.util.*;

public class FinansTakip {
    static List<Islem> islemler = new ArrayList<>();
    static Scanner sc = new Scanner(System.in);

    static class Islem {
        String aciklama;
        double miktar;
        boolean gelir;

        Islem(String aciklama, double miktar, boolean gelir) {
            this.aciklama = aciklama;
            this.miktar = miktar;
            this.gelir = gelir;
        }
    }

    static void islemEkle() {
        System.out.print('Aciklama: ');
        String a = sc.nextLine();
        System.out.print('Miktar: ');
        double m = Double.parseDouble(sc.nextLine());
        System.out.print('Gelir mi? (e/h): ');
        boolean g = sc.nextLine().equalsIgnoreCase('e');
        islemler.add(new Islem(a, m, g));
        System.out.println('Islem eklendi.');
    }

    static void raporGoster() {
        double gelir = 0, gider = 0;
        for (Islem i : islemler) {
            if (i.gelir) gelir += i.miktar;
            else gider += i.miktar;
            System.out.println((i.gelir ? '+' : '-') + i.miktar + ' TL - ' + i.aciklama);
        }
        System.out.println('\nGelir: ' + gelir + ' TL');
        System.out.println('Gider: ' + gider + ' TL');
        System.out.println('Bakiye: ' + (gelir - gider) + ' TL');
    }

    public static void main(String[] args) {
        while (true) {
            System.out.println('\n1-Islem Ekle 2-Rapor 3-Cikis');
            System.out.print('Secim: ');
            String s = sc.nextLine();
            if (s.equals('1')) islemEkle();
            else if (s.equals('2')) raporGoster();
            else if (s.equals('3')) break;
        }
    }
}

