			dosya, hata := os.OpenFile(dosyaAdi, os.O_APPEND|os.O_WRONLY, 0644)
			if hata != nil {
				fmt.Println("Hata:", hata)
			} else {
				dosya.WriteString(scanner.Text() + "\n")
				dosya.Close()
				fmt.Println("Metin eklendi.")
			}

		case "4":
			return
		}
	}
}

package main

import (
	"bufio"
	"fmt"
	"os"
)

type Soru struct {
	Metin    string
	Cevaplar [4]string
	Dogru    int
}

func main() {
	sorular := []Soru{
		{Metin: "Turkiye\'nin baskenti neresidir?",
			Cevaplar: [4]string{"Istanbul", "Ankara", "Izmir", "Bursa"}, Dogru: 2},
		{Metin: "Python programlama dilini kim gelistirmistir?",
			Cevaplar: [4]string{"Dennis Ritchie", "Guido van Rossum", "Brendan Eich", "James Gosling"}, Dogru: 2},
		{Metin: "Dunya\'nin en buyuk okyanusu hangisidir?",
			Cevaplar: [4]string{"Atlantik", "Hint", "Pasifik", "Arktik"}, Dogru: 3},
	}

	scanner := bufio.NewScanner(os.Stdin)
	puan := 0

	for i, s := range sorular {
		fmt.Printf("\n%d. %s\n", i+1, s.Metin)
		for j, c := range s.Cevaplar {
			fmt.Printf("  %d) %s\n", j+1, c)
		}
		fmt.Print("Cevabiniz (1-4): ")
		scanner.Scan()
		cevap := 0
		fmt.Sscanf(scanner.Text(), "%d", &cevap)
		if cevap == s.Dogru {
			fmt.Println("Dogru!")
			puan++
		} else {
			fmt.Printf("Yanlis! Dogru cevap: %d) %s\n", s.Dogru, s.Cevaplar[s.Dogru-1])
		}
	}

	fmt.Printf("\nToplam puan: %d/%d\n", puan, len(sorular))
	if puan == len(sorular) {
		fmt.Println("Muqemmel!")
	} else if puan > len(sorular)/2 {
		fmt.Println("Iyi is cikardin!")
	} else {
		fmt.Println("Tekrar dene!")
	}
}

import express, { Request, Response } from 'express';

interface Gorev {
    id: number;
    baslik: string;
    tamamlandi: boolean;
}

let gorevler: Gorev[] = [];
let sonrakiId = 1;
const app = express();
app.use(express.json());

app.get('/gorevler', (_req: Request, res: Response) => {
    res.json(gorevler);
});

app.get('/gorevler/:id', (req: Request, res: Response) => {
    const gorev = gorevler.find(g => g.id === parseInt(req.params.id));
    if (gorev) {
        res.json(gorev);
    } else {
        res.status(404).json({ hata: 'Gorev bulunamadi' });
    }
});

app.post('/gorevler', (req: Request, res: Response) => {
    const gorev: Gorev = {
        id: sonrakiId++,
        baslik: req.body.baslik,
        tamamlandi: false
    };
    gorevler.push(gorev);
    res.status(201).json(gorev);
});

app.put('/gorevler/:id', (req: Request, res: Response) => {
    const gorev = gorevler.find(g => g.id === parseInt(req.params.id));
    if (gorev) {
        gorev.baslik = req.body.baslik ?? gorev.baslik;
        gorev.tamamlandi = req.body.tamamlandi ?? gorev.tamamlandi;
        res.json(gorev);
    } else {
        res.status(404).json({ hata: 'Gorev bulunamadi' });
    }
});

app.delete('/gorevler/:id', (req: Request, res: Response) => {
    const index = gorevler.findIndex(g => g.id === parseInt(req.params.id));
    if (index !== -1) {
        gorevler.splice(index, 1);
        res.status(204).send();
    } else {
        res.status(404).json({ hata: 'Gorev bulunamadi' });
    }
});

app.listen(3000, () => {
    console.log('API 3000 portunda calisiyor...');
});

interface Medya {
    id: number;
    baslik: string;
    tur: 'film' | 'dizi';
    puan: number;
    izlendi: boolean;
    yil: number;
}

class MedyaListesi {
    private liste: Medya[] = [];
    private sonrakiId = 1;

    ekle(baslik: string, tur: 'film' | 'dizi', puan: number, yil: number): void {
        this.liste.push({
            id: this.sonrakiId++,
            baslik,
            tur,
            puan,
            yil,
            izlendi: false
        });
    }

    izlendiIsaretle(id: number): void {
        const medya = this.liste.find(m => m.id === id);
        if (medya) {
            medya.izlendi = true;
            console.log(`${medya.baslik} izlendi olarak isaretlendi.`);
        }
    }

    listele(filtre?: 'film' | 'dizi'): Medya[] {
        if (filtre) {
            return this.liste.filter(m => m.tur === filtre);
        }
        return this.liste;
    }

    enIyiPuanli(limit: number = 3): Medya[] {
        return [...this.liste]
            .sort((a, b) => b.puan - a.puan)
            .slice(0, limit);
    }

    izlenmeyenler(): Medya[] {
        return this.liste.filter(m => !m.izlendi);
    }

    ortalamaPuan(tur?: 'film' | 'dizi'): number {
        const filtreli = tur ? this.liste.filter(m => m.tur === tur) : this.liste;
        if (filtreli.length === 0) return 0;
        return filtreli.reduce((top, m) => top + m.puan, 0) / filtreli.length;
    }
}

const liste = new MedyaListesi();
liste.ekle('Inception', 'film', 9, 2010);
liste.ekle('Breaking Bad', 'dizi', 10, 2008);
liste.ekle('Interstellar', 'film', 8, 2014);
liste.ekle('Stranger Things', 'dizi', 8, 2016);
console.log('En iyi 3:', liste.enIyiPuanli());
console.log('Filmler:', liste.listele('film'));
console.log('Ortalama film puani:', liste.ortalamaPuan('film'));
